const inputData = $input.first().json;

const result = await new Promise((resolve, reject) => {
  const https = require('https');

  const payload = JSON.stringify({
    model: 'llama-3.3-70b-versatile',
    temperature: 0.1,
    max_tokens: 400,
    messages: [
      {
        role: 'system',
        content: 'You are an expert customer support classifier. Respond ONLY with a valid JSON object with these exact fields: category (one of: billing, technical, account, complaint, general, sales, refund, shipping), urgency (one of: low, medium, high, critical), sentiment (one of: positive, neutral, negative, very_negative), complexity (one of: simple, moderate, complex), language (ISO 639-1 code like en or es), summary (one sentence), needs_human (true or false), confidence (number 0 to 1). Return only the JSON object, no markdown, no explanation. Only set needs_human to true if: account is locked, payment failed and cannot be resolved automatically, legal threat, data loss, or customer explicitly demands human agent. Simple informational questions about billing, shipping status, or account settings should always be needs_human: false and complexity: simple.'
      },
      {
        role: 'user',
        content: `Subject: ${inputData.subject}\nFrom: ${inputData.from}\nMessage: ${inputData.message}`
      }
    ]
  });

  const options = {
    hostname: 'api.groq.com',
    path: '/openai/v1/chat/completions',
    method: 'POST',
    headers: {
      'Authorization': 'Bearer YOUR_GROQ_API_KEY',
      'Content-Type': 'application/json',
      'Content-Length': Buffer.byteLength(payload)
    }
  };

  const req = https.request(options, (res) => {
    let data = '';
    res.on('data', chunk => data += chunk);
    res.on('end', () => resolve(JSON.parse(data)));
  });

  req.on('error', reject);
  req.write(payload);
  req.end();
});

const content = result.choices[0].message.content;

let classification;
try {
  classification = JSON.parse(content.replace(/```json|```/g, '').trim());
} catch(e) {
  classification = {
    category: 'general',
    urgency: 'medium',
    sentiment: 'neutral',
    complexity: 'moderate',
    language: 'en',
    summary: 'Unable to classify - requires human review',
    needs_human: true,
    confidence: 0
  };
}

classification.confidence = parseFloat(classification.confidence) || 0;

return [{
  json: {
    ...inputData,
    classification,
    ticket_id: `TKT-${Date.now()}`,
    processed_at: new Date().toISOString(),
    ai_model: result.model
  }
}];

